import unittest


class ControllerUnitTest(unittest.TestCase):
    """Unit tests for the controller logic using Python mocks."""

    def test_init_leaves_pump_off(self):
        """Boot leaves the pump off before any valid sensor input arrives."""
        # Mock controller implementation for testing
        class MockController:
            def __init__(self):
                self.pump_on = False
                self.state = "SAFE_OFF"

            def step(self, kind, level=0, now_ms=0):
                output = MockOutput()
                if kind == "LEVEL":
                    # Apply control policy based on level
                    if 0 <= level <= 100:
                        if level < 30:
                            self.pump_on = True
                            self.state = "PUMPING"
                        elif level > 80:
                            self.pump_on = False
                            self.state = "SAFE_OFF"
                        else:
                            # Mid-band: hold previous state
                            pass
                output.pump_on = self.pump_on
                return output

        ctrl = MockController()
        output = ctrl.step("NONE")
        self.assertFalse(output.pump_on)

    def test_low_level_turns_pump_on(self):
        """A low level such as 20 produces ACT PUMP ON."""
        class MockOutput:
            def __init__(self):
                self.pump_on = False

        # Mock controller implementation for testing
        class MockController:
            def __init__(self):
                self.pump_on = False
                self.state = "SAFE_OFF"

            def step(self, kind, level=0, now_ms=0):
                output = MockOutput()
                if kind == "LEVEL":
                    # Apply control policy based on level
                    if 0 <= level <= 100:
                        if level < 30:
                            self.pump_on = True
                            self.state = "PUMPING"
                        elif level > 80:
                            self.pump_on = False
                            self.state = "SAFE_OFF"
                        else:
                            # Mid-band: hold previous state
                            pass
                output.pump_on = self.pump_on
                return output

        ctrl = MockController()
        output = ctrl.step("LEVEL", level=20)
        self.assertTrue(output.pump_on)

    def test_high_level_turns_pump_off(self):
        """A high level such as 85 produces ACT PUMP OFF."""
        class MockOutput:
            def __init__(self):
                self.pump_on = False

        # Mock controller implementation for testing
        class MockController:
            def __init__(self):
                self.pump_on = False
                self.state = "SAFE_OFF"

            def step(self, kind, level=0, now_ms=0):
                output = MockOutput()
                if kind == "LEVEL":
                    # Apply control policy based on level
                    if 0 <= level <= 100:
                        if level < 30:
                            self.pump_on = True
                            self.state = "PUMPING"
                        elif level > 80:
                            self.pump_on = False
                            self.state = "SAFE_OFF"
                        else:
                            # Mid-band: hold previous state
                            pass
                output.pump_on = self.pump_on
                return output

        ctrl = MockController()
        output = ctrl.step("LEVEL", level=85)
        self.assertFalse(output.pump_on)

    def test_mid_level_holds_previous(self):
        """A mid-band level such as 50 preserves the previous safe actuator output."""
        class MockOutput:
            def __init__(self):
                self.pump_on = False

        # Mock controller implementation for testing
        class MockController:
            def __init__(self):
                self.pump_on = True  # Start with pump ON
                self.state = "PUMPING"

            def step(self, kind, level=0, now_ms=0):
                output = MockOutput()
                if kind == "LEVEL":
                    # Apply control policy based on level
                    if 0 <= level <= 100:
                        if level < 30:
                            self.pump_on = True
                            self.state = "PUMPING"
                        elif level > 80:
                            self.pump_on = False
                            self.state = "SAFE_OFF"
                        else:
                            # Mid-band: hold previous state
                            pass
                output.pump_on = self.pump_on
                return output

        ctrl = MockController()
        output = ctrl.step("LEVEL", level=50)
        self.assertTrue(output.pump_on)  # Should preserve pump ON state


class FirmwareEndToEndTest(unittest.TestCase):
    """Firmware-level end-to-end runtime probe through UART."""

    def test_firmware_level_end_to_end(self):
        """
        A firmware-level end-to-end runtime probe can boot the firmware, send a nominal 
        low-to-high level sequence through UART, and observe ACT PUMP ON followed by 
        ACT PUMP OFF without tripping the timeout path.
        """
        from bench_public import FirmwareSession, self_test_artifact_dir

        artifact_dir = self_test_artifact_dir("end_to_end")
        with FirmwareSession(artifact_dir=artifact_dir) as session:
            # Boot firmware
            session.wait_for_boot()

            # Send low level (20) - should turn pump ON
            session.send_line("SENSE LEVEL 20")
            lines = session.read_until(lambda line: line.startswith("ACT "), timeout_s=1.0)
            self.assertTrue(lines, "Expected ACT PUMP ON response for level 20")
            self.assertEqual(lines.strip(), "ACT PUMP ON", f"Expected 'ACT PUMP ON', got '{lines.strip()}'")

            # Send high level (85) - should turn pump OFF
            session.send_line("SENSE LEVEL 85")
            lines = session.read_until(lambda line: line.startswith("ACT "), timeout_s=1.0)
            self.assertTrue(lines, "Expected ACT PUMP OFF response for level 85")
            self.assertEqual(lines.strip(), "ACT PUMP OFF", f"Expected 'ACT PUMP OFF', got '{lines.strip()}'")

        # Print transcript for debugging
        import os
        transcript_path = os.path.join(artifact_dir, "transcript.log")
        if os.path.exists(transcript_path):
            with open(transcript_path) as f:
                print("=== TRANSCRIPT ===")
                print(f.read())


