#include "protocol.h"

#include <ctype.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void protocol_reset_input(protocol_input_t *input)
{
    if (input == NULL) {
        return;
    }

    input->kind = PROTOCOL_INPUT_NONE;
    input->level = 0;
}

static void protocol_trim_copy(const char *line, char *buffer, size_t buffer_size)
{
    size_t source_length;
    size_t start = 0U;
    size_t end;
    size_t length;

    if (buffer_size == 0U) {
        return;
    }

    buffer[0] = '\0';
    if (line == NULL) {
        return;
    }

    source_length = strnlen(line, buffer_size - 1U);
    while ((start < source_length) && isspace((unsigned char) line[start])) {
        start++;
    }

    end = source_length;
    while ((end > start) && isspace((unsigned char) line[end - 1U])) {
        end--;
    }

    length = end - start;
    memcpy(buffer, line + start, length);
    buffer[length] = '\0';
}

static bool protocol_parse_level_value(const char *token, int *level)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (level == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 100L)) {
        return false;
    }

    *level = (int) parsed;
    return true;
}

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input)
{
    char scratch[PROTOCOL_MAX_LINE_LENGTH];
    char *save = NULL;
    char *first;
    char *second;
    char *third;
    char *fourth;
    int level;

    protocol_reset_input(input);
    protocol_trim_copy(line, scratch, sizeof(scratch));
    if (scratch[0] == '\0') {
        return PROTOCOL_PARSE_IGNORED;
    }

    first = strtok_r(scratch, " \t", &save);
    second = strtok_r(NULL, " \t", &save);
    third = strtok_r(NULL, " \t", &save);
    fourth = strtok_r(NULL, " \t", &save);

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "LEVEL") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_level_value(third, &level)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_LEVEL;
            }
            return PROTOCOL_PARSE_INVALID_LEVEL;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_LEVEL;
            input->level = level;
        }
        return PROTOCOL_PARSE_LEVEL;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "FAULT") == 0) && (strcmp(second, "SENSOR_TIMEOUT") == 0) && (third == NULL)) {
        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_SENSOR_TIMEOUT;
        }
        return PROTOCOL_PARSE_SENSOR_TIMEOUT;
    }

    return PROTOCOL_PARSE_IGNORED;
}

bool protocol_serialize_act_pump(bool pump_on, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT PUMP %s\n", pump_on ? "ON" : "OFF");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "DBG %s\n", message != NULL ? message : "");
    return (written >= 0) && ((size_t) written < buffer_size);
}

def scenario_specs(task_spec: TaskSpec | None = None) -> dict[str, ScenarioSpec]:
    return {
        "smoke": ScenarioSpec(name="smoke", initial_level=20, max_steps=8, send_valid_until_ms=0),
        "happy_path": ScenarioSpec(name="happy_path", initial_level=20, max_steps=28),
        "sensor_timeout": ScenarioSpec(name="sensor_timeout", initial_level=20, max_steps=22, send_valid_until_ms=300),
        "malformed_frame": ScenarioSpec(name="malformed_frame", initial_level=20, max_steps=10, send_valid_until_ms=0, inject_invalid_at_ms=100),
    }


def _plant_config(task_spec: TaskSpec) -> TankPlantConfig:
    payload = dict(task_spec.payload.get("plant", {}))
    sensor_range = task_spec.primary_sensor_range or (0, 100)
    return TankPlantConfig(
        tick_ms=int(payload.get("tick_ms", 100)),
        fill_delta=int(payload.get("fill_delta", 6)),
        drain_delta=int(payload.get("drain_delta", 1)),
        min_level=int(payload.get("min_level", sensor_range[0])),
        max_level=int(payload.get("max_level", sensor_range[1])),
    )

#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on level */
        if (input.level < 0 || input.level > 100) {
            /* Invalid level - fail safe to OFF */
            controller_set_safe_off(controller);
        } else if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            /* Low level - turn pump ON */
            controller->pump_on = true;
            controller->state = CONTROLLER_STATE_PUMPING;
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* High level - turn pump OFF */
            controller->pump_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else {
            /* Mid-band: hold previous safe output */
            controller->state = CONTROLLER_STATE_HOLDING;
            /* Keep current pump_on state unchanged */
        }

        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_off(controller);
        break;
    }

    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

